// Detectar tipo de resultado
const input = $input.first().json;
const isError = !!input.error;
const currentCountry = $('Loop Over Items').first().json.country


// En el loop tenemos los datos de la bandeja
const bandeja = input;
const country = bandeja.country || currentCountry || 'UNKNOWN';

let messageType = 'success';
let errorMsg = '';

if (isError) {
  // Distinguir si es error de login o de reinicio
  // Heurística: si tenemos StatusCode y no hay token parseado, fue login
  // Si llegamos al nodo de reinicio pero falla, fue restart

  // Por ahora: asumir que si Error en WebService Log In, es login_error
  // Si error después de token, es restart_error
  // Chequeamos por presencia de SesionId

  if (input.SesionId) {
    messageType = 'restart_error';
  } else {
    messageType = 'login_error';
  }
  errorMsg = input.error?.message || String(input.error).slice(0, 200);
} else {
  // Si no hay error, pero viene de ReiniciarBandejaArchivos, validar SOAP response
  const raw = typeof input.data === 'string' ? input.data : JSON.stringify(input || {});
  if (/soap:Fault|<faultstring>/i.test(raw)) {
    messageType = 'restart_error';
    const faultMatch = raw.match(/<faultstring>(.*?)<\/faultstring>/);
    errorMsg = faultMatch ? faultMatch[1] : 'SOAP Fault en respuesta';
  }
}

// Limpiar mensaje de error si viene del servidor (SOAP Exception)
// Extrae solo el mensaje de la excepción, eliminando el stack trace
if (errorMsg && errorMsg.includes('Exception: ')) {
  try {
    errorMsg = errorMsg.split('Exception: ')[1].split(/\r\n|\n/)[0].trim();
  } catch (e) {
    // Si falla la limpieza, mantener el original
  }
}

return [{
  json: {
    messageType,
    country,
    errorMsg: errorMsg || '',
    timestamp: new Date().toISOString(),
    ws_status: 'fail',
    ws_response_raw: errorMsg.slice(0, 2000) || ''
  }
}];

// 1. Capturamos el ítem actual que se está validando en la vuelta del bucle.
// IMPORTANTE: Asegúrate de que el nombre del nodo entre comillas coincida exactamente con tu nodo de bucle.
const currentItem = $('Loop Over Items').item.json;

// 2. Extraemos el país desde el elemento actual del loop
const country = currentItem.pais;

// 3. Extraemos las demás variables. Priorizamos el elemento del bucle por si también viajan allí, 
// con fallback al input inmediato del nodo anterior si es necesario.
const msgType = currentItem.messageType || $input.first().json.messageType;
const err = currentItem.errorMsg || $input.first().json.errorMsg;
const timestamp = currentItem.timestamp || $input.first().json.timestamp;

// 4. Diccionario de zonas horarias por país
const timezones = {
  'ARG': 'America/Argentina/Buenos_Aires',
  'ECU': 'America/Guayaquil',
  'PER': 'America/Lima'
};

// 5. Configuración de zona horaria y visualización segura
const selectedTimeZone = timezones[country] || 'America/Argentina/Buenos_Aires';
const displayCountry = country || 'ARG';

// 6. Formateo de fecha y hora localizadas
const time = new Date(timestamp || Date.now()).toLocaleString('es-AR', {
  timeZone: selectedTimeZone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit'
});

let text = '';

// 7. Formateo de la salida en HTML con la estructura de título solicitada
if (msgType === 'success') {
  text = `✅ <strong>REINICIO EXITOSO - BANDEJA ARCHIVOS KN - ${displayCountry}</strong><br>${time}`;
} else if (msgType === 'login_error') {
  text = `❌ <strong>ERROR DE CONEXIÓN - BANDEJA ARCHIVOS KN - ${displayCountry}</strong><br><strong>Error:</strong> ${err}<br>${time}`;
} else if (msgType === 'restart_error') {
  text = `⚠️ <strong>FALLA AL REINICIAR - BANDEJA ARCHIVOS KN - ${displayCountry}</strong><br><strong>Error:</strong> ${err}<br>${time}`;
}

return [{
  json: {
    text
  }
}];

// Recupera los datos de Set Error Log o Set Success para guardar en tabla
// Se ejecuta DENTRO del loop, después de enviar el mensaje

let messageType = 'success';
let country = 'UNKNOWN';
let errorMsg = '';
let timestamp = new Date().toISOString();

let teamsMessage = $input.first().json

// Intentar obtener de Set Error Log (si hubo error)
try {
  const errorLogData = $('Set Error Log').first().json;
  if (errorLogData && errorLogData.messageType) {
    messageType = errorLogData.messageType;
    country = errorLogData.country || country;
    errorMsg = errorLogData.errorMsg || '';
    timestamp = errorLogData.errorTimestamp || timestamp;
  }
} catch (e) {
  // Si no hay Set Error Log, fue Set Success
  try {
    const successData = $('Set Success').first().json;
    if (successData) {
      messageType = 'success';
      timestamp = successData.timestamp || timestamp;
      // country se obtiene del Loop
      country = $('Loop Over Items').first().json.pais || country;
    }
  } catch (e2) {
    // Fallback: usar datos del input actual
    const input = $input.first().json;
    country = input.country || country;
  }
}

return [{
  json: {
    timestamp,
    entorno: country,
    ws_status: messageType === 'success' ? 'success' : 'fail',
    ws_response_raw: errorMsg,
    resultado: messageType === 'success' ? 'success' : 'fail',
    teamsMsgId: teamsMessage.id,
    teamsTimestamp: teamsMessage.createdDateTime,
    teamsMsg: teamsMessage.messageType,
    executionId: $execution.id
  }
}];

// Procesa un resultado exitoso de reinicio
// Devuelve estructura normalizada igual a Set Error Log
const input = $input.first().json;
const country = input.country || $('Loop Over Items').first().json.country || 'UNKNOWN';

return [{
  json: {
    messageType: 'success',
    country,
    errorMsg: null,
    timestamp: new Date().toISOString(),
    ws_status: 'success',
    ws_response_raw: null
  }
}];
